// modules/Problems/services/ProblemsService.js
class ProblemsService {
  static async listProblems({ limit, difficulty, tags, includeComponents }) {
    // Fetch problems from DB or source with filters applied (limit, difficulty, tags)
    // For demonstration, assume this.problems is the full list
    let filteredProblems = this.problems || [];

    if (difficulty !== undefined) {
      filteredProblems = filteredProblems.filter(problem =>
        problem.components.some(c => c.difficulty === difficulty)
      );
    }

    if (tags && tags.length > 0) {
      filteredProblems = filteredProblems.filter(problem =>
        problem.components.some(c => tags.some(tag => c.tags.includes(tag)))
      );
    }

    if (limit !== undefined) {
      filteredProblems = filteredProblems.slice(0, limit);
    }

    const response = {
      problems: filteredProblems,
      metadata: {},
    };

    if (includeComponents) {
      // Aggregate language and status totals for filtered+limited problems
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      filteredProblems.forEach(problem => {
        problem.components.forEach(component => {
          // Only count components matching difficulty and tags filters
          if (
            (difficulty === undefined || component.difficulty === difficulty) &&
            (tags === undefined || tags.length === 0 || tags.some(tag => component.tags.includes(tag)))
          ) {
            componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
            componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
          }
        });
      });

      response.metadata.componentLanguageTotals = componentLanguageTotals;
      response.metadata.componentStatusTotals = componentStatusTotals;
    }

    return response;
  }
}

module.exports = ProblemsService;
